-- Criar stored procedure
CREATE PROCEDURE sp_BuscarClientesPorCidade
    @Cidade VARCHAR(100),
    @ApenasAtivos BIT = 1  -- parâmetro com valor padrão
AS
BEGIN
    SET NOCOUNT ON;  -- evita mensagem '(n rows affected)'

    SELECT
        Id,
        Nome,
        Email
    FROM Clientes
    WHERE Cidade = @Cidade
        AND (@ApenasAtivos = 0 OR Ativo = 1);
END;

-- Executar
EXEC sp_BuscarClientesPorCidade @Cidade = 'São Paulo';
EXEC sp_BuscarClientesPorCidade @Cidade = 'Rio de Janeiro', @ApenasAtivos = 0;

CREATE PROCEDURE sp_InserirPedido
    @ClienteId INT,
    @Valor DECIMAL(10,2),
    @PedidoId INT OUTPUT  -- parâmetro de saída
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        INSERT INTO Pedidos (ClienteId, Valor, DataPedido, Status)
        VALUES (@ClienteId, @Valor, GETDATE(), 'Pendente');

        SET @PedidoId = SCOPE_IDENTITY();  -- Id gerado
    END TRY
    BEGIN CATCH
        SET @PedidoId = -1;
        THROW;  -- re-lança o erro
    END CATCH;
END;

-- Usar com OUTPUT
DECLARE @NovoId INT;
EXEC sp_InserirPedido
    @ClienteId = 5,
    @Valor = 1500.00,
    @PedidoId = @NovoId OUTPUT;
SELECT @NovoId AS PedidoGerado;
